#include "PluginEditor.h"
#include "GUI/Theme.h"
ReverbRomanticAudioProcessorEditor::ReverbRomanticAudioProcessorEditor(ReverbRomanticAudioProcessor& p):AudioProcessorEditor(&p),processor(p){setLookAndFeel(&laf);setSize(1180,720);setResizable(true,true);title.setText("REVERB ROMANTIC",juce::dontSendNotification);title.setJustificationType(juce::Justification::centred);title.setColour(juce::Label::textColourId,RomanticTheme::accentBright);title.setFont(juce::Font(juce::FontOptions(30)).boldened());subtitle.setText("HYBRID FDN 16x16",juce::dontSendNotification);subtitle.setJustificationType(juce::Justification::centred);subtitle.setColour(juce::Label::textColourId,RomanticTheme::dim);addAndMakeVisible(title);addAndMakeVisible(subtitle);const char* ids[]={Parameters::IDs::mix,Parameters::IDs::decay,Parameters::IDs::time,Parameters::IDs::preDelay,Parameters::IDs::size,Parameters::IDs::width,Parameters::IDs::warmth,Parameters::IDs::brightness,Parameters::IDs::diffusion,Parameters::IDs::density,Parameters::IDs::modulation,Parameters::IDs::bloom,Parameters::IDs::ducking,Parameters::IDs::lowCut,Parameters::IDs::highCut,Parameters::IDs::output};const char* suffix[]={" %"," s"," x"," ms"," %"," %"," dB"," dB"," %"," %"," %"," %"," %"," Hz"," Hz"," dB"};for(int i=0;i<16;++i){setup(sliders[(size_t)i],suffix[i]);attachments[(size_t)i]=std::make_unique<SA>(processor.apvts,ids[i],sliders[(size_t)i]);}addAndMakeVisible(freeze);addAndMakeVisible(bypass);freezeA=std::make_unique<BA>(processor.apvts,Parameters::IDs::freeze,freeze);bypassA=std::make_unique<BA>(processor.apvts,Parameters::IDs::bypass,bypass);startTimerHz(30);}
ReverbRomanticAudioProcessorEditor::~ReverbRomanticAudioProcessorEditor(){setLookAndFeel(nullptr);}void ReverbRomanticAudioProcessorEditor::setup(juce::Slider& s,const juce::String& suf){s.setSliderStyle(juce::Slider::RotaryHorizontalVerticalDrag);s.setTextBoxStyle(juce::Slider::TextBoxBelow,false,76,20);s.setTextValueSuffix(suf);s.setMouseDragSensitivity(220);addAndMakeVisible(s);}void ReverbRomanticAudioProcessorEditor::paint(juce::Graphics& g){juce::ColourGradient bg(RomanticTheme::bgTop,0,0,RomanticTheme::bgBottom,0,(float)getHeight(),false);g.setGradientFill(bg);g.fillAll();auto b=getLocalBounds().reduced(20).toFloat();b.removeFromTop(80);g.setColour(RomanticTheme::panel.withAlpha(.75f));g.fillRoundedRectangle(b,14);g.setColour(RomanticTheme::border);g.drawRoundedRectangle(b,14,1);auto meter=juce::Rectangle<float>((float)getWidth()-65,125,10,500);g.setColour(juce::Colours::black.withAlpha(.5f));g.fillRoundedRectangle(meter,3);float v=juce::jlimit(0.0f,1.0f,processor.getOutputPeakLeft());auto level=meter.withY(meter.getBottom()-meter.getHeight()*v);g.setColour(RomanticTheme::accentBright);g.fillRoundedRectangle(level,3);}
void ReverbRomanticAudioProcessorEditor::resized(){auto b=getLocalBounds().reduced(28);auto h=b.removeFromTop(68);title.setBounds(h.removeFromTop(42));subtitle.setBounds(h);b.removeFromTop(30);b.removeFromRight(80);int cw=b.getWidth()/6,rh=b.getHeight()/3;for(int row=0;row<3;++row){auto rr=b.removeFromTop(rh);for(int col=0;col<6;++col){int idx=row*6+col;if(idx>=16)break;sliders[(size_t)idx].setBounds(rr.removeFromLeft(cw).reduced(10,12));}}auto buttons=getLocalBounds().removeFromBottom(52).removeFromRight(250).reduced(8);freeze.setBounds(buttons.removeFromLeft(110));buttons.removeFromLeft(10);bypass.setBounds(buttons.removeFromLeft(110));}
